            ],
        );
        produces
    }

    async fn new(config: Self::Config, db: Arc<DatabaseService>) -> Result<Self> {
        Ok(Self { config, db })
    }

    async fn run(&mut self) -> Result<()> {
        let listener = KittyListener::new(
            self.config.kitty.clone(),
            Arc::clone(&self.db),
        )?;

        listener.start().await
    }
}

